INSERT INTO `messages` VALUES (1,9,4,'hi',NULL,NULL,NULL,NULL,NULL,'hi','SENT',0,'2026-05-18 06:15:28','2026-05-18 06:15:28',NULL),(2,17,4,'hiiii',NULL,NULL,NULL,NULL,NULL,'hiiii','SENT',0,'2026-05-19 19:02:54','2026-05-19 19:02:54',NULL),(3,4,17,'≡ƒñû AI Assistant\nHello ben ten juls. I\'m AjesAI, your virtual assistant in the AJES Crier system. How can I assist you with AJES-related matters today?',NULL,NULL,NULL,NULL,NULL,NULL,'READ',1,'2026-05-19 19:02:55','2026-05-19 19:10:11',NULL),(4,17,4,'what are those subject in grade 2',NULL,NULL,NULL,NULL,NULL,'what are those subject in grade 2','SENT',0,'2026-05-19 19:03:15','2026-05-19 19:03:15',NULL),(5,4,17,'≡ƒñû AI Assistant\nHello ben ten juls, I can help you with that. However, the AJES Crier system doesn\'t provide a list of specific subjects for Grade 2. You can try contacting your teacher or the Guidance office through the chat for more information about your subjects. They\'ll be happy to help you with that.',NULL,NULL,NULL,NULL,NULL,NULL,'READ',1,'2026-05-19 19:03:15','2026-05-19 19:10:11',NULL),(6,17,4,'how many section in grade 2',NULL,NULL,NULL,NULL,NULL,'how many section in grade 2','SENT',0,'2026-05-19 19:03:55','2026-05-19 19:03:55',NULL),(7,4,17,'≡ƒñû AI Assistant\nIn Grade 2, there is only 1 section available, which is Grade 2 - Mahogany.',NULL,NULL,NULL,NULL,NULL,NULL,'READ',1,'2026-05-19 19:03:56','2026-05-19 19:10:11',NULL),(8,17,4,'and who are those student that already enrolled in grade 2 mahogany',NULL,NULL,NULL,NULL,NULL,'and who are those student that already enrolled in grade 2 mahogany','SENT',0,'2026-05-19 19:04:38','2026-05-19 19:04:38',NULL),(9,4,17,'≡ƒñû AI Assistant\nI\'m happy to help you with AJES-related questions. However, I don\'t have access to real-time student enrollment data or specific student information. For confidentiality and privacy reasons, I can only provide general information about the school. If you need to know the list of students enrolled in Grade 2 Mahogany, I suggest contacting the school office or messaging the Principal or Guidance directly in chat.',NULL,NULL,NULL,NULL,NULL,NULL,'READ',1,'2026-05-19 19:04:39','2026-05-19 19:10:11',NULL),(10,17,4,'what time does the school starts',NULL,NULL,NULL,NULL,NULL,'what time does the school starts','SENT',0,'2026-05-19 19:06:28','2026-05-19 19:06:28',NULL),(11,4,17,'≡ƒñû AI Assistant\nI\'m happy to help you with AJES-related questions. However, the school start time is not specified in the AJES Crier System Knowledge. I suggest checking the school announcements or contacting the Principal or Guidance office directly through chat for the most accurate and up-to-date information.',NULL,NULL,NULL,NULL,NULL,NULL,'READ',1,'2026-05-19 19:06:29','2026-05-19 19:10:11',NULL),(12,17,4,'what time does the school starts',NULL,NULL,NULL,NULL,NULL,'what time does the school starts','SENT',0,'2026-05-19 19:10:27','2026-05-19 19:10:27',NULL),(13,4,17,'≡ƒñû AI Assistant\nThe school starts at 7:30 AM.',NULL,NULL,NULL,NULL,NULL,NULL,'SENT',1,'2026-05-19 19:10:30','2026-05-19 19:10:30',NULL),(14,17,4,'and the classs end what time?',NULL,NULL,NULL,NULL,NULL,'and the classs end what time?','SENT',0,'2026-05-19 19:10:52','2026-05-19 19:10:52',NULL),(15,4,17,'≡ƒñû AI Assistant\nAccording to the AJES standard class schedule, dismissal time is 3:30 PM (15:30).',NULL,NULL,NULL,NULL,NULL,NULL,'SENT',1,'2026-05-19 19:10:53','2026-05-19 19:10:53',NULL),(16,17,4,'and the recess',NULL,NULL,NULL,NULL,NULL,'and the recess','SENT',0,'2026-05-19 19:11:27','2026-05-19 19:11:27',NULL),(17,4,17,'≡ƒñû AI Assistant\nThe recess schedule for AJES is from 09:10 to 09:30.',NULL,NULL,NULL,NULL,NULL,NULL,'SENT',1,'2026-05-19 19:11:28','2026-05-19 19:11:28',NULL),(18,17,4,'generate a code using c++',NULL,NULL,NULL,NULL,NULL,'generate a code using c++','SENT',0,'2026-05-19 19:11:56','2026-05-19 19:11:56',NULL),(19,4,17,'≡ƒñû AI Assistant\nI\'m happy to help you with your question, but I must politely refuse as it\'s not related to Ano Jay Elementary School (AJES). I can only provide information and answer questions about AJES, its announcements, sections, enrolled students, class schedules, chat, and school office procedures. \n\nIf you have any questions or concerns about AJES, I\'d be more than happy to help. For example, I can provide you with information about the school schedule, enrolled students in a specific grade or sectio...',NULL,NULL,NULL,NULL,NULL,NULL,'SENT',1,'2026-05-19 19:11:57','2026-05-19 19:11:57',NULL),(20,17,4,'how many section in grade 2',NULL,NULL,NULL,NULL,NULL,'how many section in grade 2','SENT',0,'2026-05-19 19:12:50','2026-05-19 19:12:50',NULL),(21,4,17,'≡ƒñû AI Assistant\nIn Grade 2, there is 1 section listed: Grade 2 - Mahogany.',NULL,NULL,NULL,NULL,NULL,NULL,'SENT',1,'2026-05-19 19:12:50','2026-05-19 19:12:50',NULL),(22,17,4,'and what the others section is available',NULL,NULL,NULL,NULL,NULL,'and what the others section is available','SENT',0,'2026-05-19 19:13:11','2026-05-19 19:13:11',NULL),(23,4,17,'≡ƒñû AI Assistant\nHello ben ten juls. Based on the AJES Crier system knowledge, the available sections are:\n\n1. Grade 1 - A\n2. Grade 2 - Mahogany\n3. Grade 3 - A\n4. Grade 6 - A\n\nThese are the sections listed in the system. If you\'re looking for other sections, I suggest checking the Announcements or visiting the school office for more information.',NULL,NULL,NULL,NULL,NULL,NULL,'SENT',1,'2026-05-19 19:13:12','2026-05-19 19:13:12',NULL),(24,17,4,'no only in g2 theres a 3 sections',NULL,NULL,NULL,NULL,NULL,'no only in g2 theres a 3 sections','SENT',0,'2026-05-19 19:13:33','2026-05-19 19:13:33',NULL),(25,4,17,'≡ƒñû AI Assistant\nIt seems you are referring to Grade 2 having 3 sections. However, according to the AJES Crier system knowledge, I only have information on one Grade 2 section, which is Grade 2 - Mahogany. If you\'re looking for information on other Grade 2 sections, I suggest checking the Announcements or visiting the school office for the most up-to-date information.',NULL,NULL,NULL,NULL,NULL,NULL,'SENT',1,'2026-05-19 19:13:35','2026-05-19 19:13:35',NULL),(26,17,4,'and who are those student that already enrolled in grade 2 mahogany',NULL,NULL,NULL,NULL,NULL,'and who are those student that already enrolled in grade 2 mahogany','SENT',0,'2026-05-19 19:13:48','2026-05-19 19:13:48',NULL),(27,4,17,'≡ƒñû AI Assistant\nIn Grade 2 - Mahogany, the enrolled student is:\n- baste malilay oakdol',NULL,NULL,NULL,NULL,NULL,NULL,'SENT',1,'2026-05-19 19:13:49','2026-05-19 19:13:49',NULL),(28,17,4,'what are those subject in g2 list it',NULL,NULL,NULL,NULL,NULL,'what are those subject in g2 list it','SENT',0,'2026-05-19 19:15:10','2026-05-19 19:15:10',NULL),(29,4,17,'≡ƒñû AI Assistant\nI\'m happy to help you, Ben. However, the subject list for Grade 2 is not provided in the AJES Crier system knowledge block. You can check the Announcements or visit the school office for more information about the subjects in Grade 2.',NULL,NULL,NULL,NULL,NULL,NULL,'SENT',1,'2026-05-19 19:15:11','2026-05-19 19:15:11',NULL),(30,16,4,'hii',NULL,NULL,NULL,NULL,NULL,'hii','SENT',0,'2026-05-19 19:19:41','2026-05-19 19:19:41',NULL),(31,14,4,'hiii',NULL,NULL,NULL,NULL,NULL,'hiii','SENT',0,'2026-05-19 19:31:19','2026-05-19 19:31:19',NULL),(32,14,4,'hello',NULL,NULL,NULL,NULL,NULL,'hello','SENT',0,'2026-05-19 19:31:35','2026-05-19 19:31:35',NULL),(33,14,4,'hii',NULL,NULL,NULL,NULL,NULL,'hii','SENT',0,'2026-05-19 19:34:42','2026-05-19 19:34:42',NULL),(34,4,14,'≡ƒñû AI Assistant\nHello Baste. How can I assist you today regarding our school, AJES?',NULL,NULL,NULL,NULL,NULL,NULL,'READ',1,'2026-05-19 19:34:42','2026-05-19 19:57:32',NULL),(35,14,4,'do you know what is my grade and section?',NULL,NULL,NULL,NULL,NULL,'do you know what is my grade and section?','SENT',0,'2026-05-19 19:35:28','2026-05-19 19:35:28',NULL),(36,4,14,'≡ƒñû AI Assistant\nYes, I do. You are enrolled in Grade 2, Section Mahogany. Your class adviser is Malik Malik Malik.',NULL,NULL,NULL,NULL,NULL,NULL,'READ',1,'2026-05-19 19:35:29','2026-05-19 19:57:32',NULL),(37,14,4,'do you know about others grade like grade 1',NULL,NULL,NULL,NULL,NULL,'do you know about others grade like grade 1','SENT',0,'2026-05-19 19:35:54','2026-05-19 19:35:54',NULL),(38,4,14,'≡ƒñû AI Assistant\nI\'m happy to help you, but as a student in Grade 2 - Mahogany, I can only provide information about your own class and section. I\'m not allowed to share information about other grades, such as Grade 1. This is to ensure your privacy and the privacy of other students.\n\nIf you have any questions about your own class or section, I\'d be happy to try and help. For example, I can tell you about your classmates in Grade 2 - Mahogany or your class schedule. Just let me know how I can assist you!',NULL,NULL,NULL,NULL,NULL,NULL,'READ',1,'2026-05-19 19:35:55','2026-05-19 19:57:32',NULL),(39,14,4,'okay what time the class start and list our subject and time',NULL,NULL,NULL,NULL,NULL,'okay what time the class start and list our subject and time','SENT',0,'2026-05-19 19:36:28','2026-05-19 19:36:28',NULL),(40,4,14,'≡ƒñû AI Assistant\nKumusta, Baste. Our class, Grade 2 - Mahogany, starts at 7:30 AM. However, I don\'t see the specific subject schedule in our AJES Crier knowledge block. You can check the school announcements or ask our class adviser, Malik Malik Malik, for the detailed subject schedule.',NULL,NULL,NULL,NULL,NULL,NULL,'READ',1,'2026-05-19 19:36:29','2026-05-19 19:57:32',NULL),(41,14,4,'list does subject that I enrolled',NULL,NULL,NULL,NULL,NULL,'list does subject that I enrolled','SENT',0,'2026-05-19 19:36:58','2026-05-19 19:36:58',NULL),(42,4,14,'≡ƒñû AI Assistant\nI\'m happy to help you, Baste. However, the subjects you are enrolled in are not listed in the AJES Crier system knowledge block. You can check the Announcements or visit the school office to get the list of subjects you are enrolled in for Grade 2 - Mahogany.',NULL,NULL,NULL,NULL,NULL,NULL,'READ',1,'2026-05-19 19:36: